import React from 'react';
import { Link } from 'react-router-dom';


const Test = ({projects}) => {
    return (
      <div className="project-list">
      {projects.map(project => {
          const nameTrim = project.name.replace(/\s/g, "");
          const nameLower = nameTrim.toUpperCase;
          return project.desc !== '' ? (

              <div className="project">
                <Link className="works-item" to={{
                pathname: `/project/${nameLower}`,
                state: {
                  test: `${ project.name }`,
                }
                }}>
                  <p>Name: { project.name }</p>
                </Link>
                <p>Desc: { project.desc }</p>
              </div>
          ) :  null
        })
       }
      </div>
    )
}

export default Test;
